const d = $input.item.json;
const s = d.summary;
let h = '<h2 style="font-family:sans-serif">Competitor Intelligence: ' + d.brand + '</h2>';
h += '<p style="font-family:sans-serif">Run: ' + new Date().toLocaleDateString('en-IN') + '</p>';
h += '<table style="border-collapse:collapse;width:100%;font-family:sans-serif;font-size:14px">';
h += '<tr style="background:#f0f0f0"><th style="padding:8px;border:1px solid #ddd">Metric</th><th style="padding:8px;border:1px solid #ddd">Count</th></tr>';
h += '<tr><td style="padding:8px;border:1px solid #ddd">New Products</td><td style="padding:8px;border:1px solid #ddd;text-align:center">' + s.new_count + '</td></tr>';
h += '<tr><td style="padding:8px;border:1px solid #ddd">Price Changes</td><td style="padding:8px;border:1px solid #ddd;text-align:center">' + s.updated_count + '</td></tr>';
h += '<tr><td style="padding:8px;border:1px solid #ddd">Removed</td><td style="padding:8px;border:1px solid #ddd;text-align:center">' + s.removed_count + '</td></tr>';
h += '</table>';
if (d.new_products?.length) {
  h += '<h3 style="color:#2e7d32;font-family:sans-serif">New Products</h3><ul style="font-family:sans-serif">';
  for (const p of d.new_products) {
    h += '<li><b>' + p.name + '</b> Rs.' + (p.price||'N/A');
    if (p.mrp) h += ' <span style="text-decoration:line-through;color:#999">Rs.' + p.mrp + '</span>';
    h += ' [' + (p.category||'') + ']</li>';
  }
  h += '</ul>';
}
if (d.updated_products?.length) {
  h += '<h3 style="color:#e65100;font-family:sans-serif">Price / Detail Changes</h3><ul style="font-family:sans-serif">';
  for (const p of d.updated_products) {
    const up = parseFloat(p.price_delta) > 0;
    const col = up ? '#c62828' : '#2e7d32';
    h += '<li><b>' + p.name + '</b>: Rs.' + p.old_price + ' to <span style="color:' + col + '">Rs.' + p.price + '</span>';
    if (Math.abs(parseFloat(p.price_delta)) > 0) h += ' (' + (up ? '+' : '') + p.price_delta + ')';
    if (p.mrp) h += ' | MRP Rs.' + p.mrp;
    h += '</li>';
  }
  h += '</ul>';
}
if (d.removed_products?.length) {
  h += '<h3 style="color:#888;font-family:sans-serif">Removed</h3><ul style="font-family:sans-serif">';
  for (const n of d.removed_products) h += '<li>' + n + '</li>';
  h += '</ul>';
}
h += '<p style="font-family:sans-serif"><a href="https://docs.google.com/spreadsheets/d/1FDTqrcWRbU5v35FirKleCYwbC3W2E6acQ9lx0wCTeUA">Open Catalogue Sheet</a></p>';
return [{ json: { brand: d.brand, html: h, subject: 'Competitor Alert: ' + d.brand + ' (' + s.new_count + ' new, ' + s.updated_count + ' changed, ' + s.removed_count + ' removed)' } }];

// ── MARKDOWN CLEANER — trim tail junk, preserve product content ─────────────
const md = $input.item.json.markdown || '';
let brand = '';
let sheetTab = '';

try {
  brand = $('Map Brand Fields').item.json.brand || '';
  sheetTab = $('Map Brand Fields').item.json.sheet_tab || '';
} catch (error) {
  console.error('Error accessing Map Brand Fields:', error);
}

// Step 1: Split into lines for targeted removal
let lines = md.split('\n');

// Step 2: Detect where "junk zone" starts — common footer/noise signals
const JUNK_SIGNALS = [
  /^#+\s*(footer|legal|privacy|terms|cookie|newsletter|subscribe|follow us|social|contact us|copyright|sitemap|faq|help center|returns|shipping policy|about us|careers|press)/i,
  /^#+\s*(you may also (like|love)|related products|recently viewed|recommended|trending|bestsellers outside)/i,
  /^\*{0,2}(©|copyright|\(c\))\s*\d{4}/i,
  /^(all rights reserved|privacy policy|terms of (use|service)|refund policy)/i,
];

let cutLine = lines.length; // default: keep everything

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (JUNK_SIGNALS.some(rx => rx.test(line))) {
    // Only cut if we're past the first 30% of the document
    // (avoids cutting real content that happens to match early)
    if (i > lines.length * 0.3) {
      cutLine = i;
      break;
    }
  }
}

lines = lines.slice(0, cutLine);

// Step 3: Remove nav link dumps — lines that are just a pile of [text](url) with no product info
// A "link dump" = 5+ consecutive lines that are only markdown links, no prices, no descriptions
let cleaned = [];
let linkRunCount = 0;
const LINK_ONLY_LINE = /^\s*[-*]?\s*\[.+?\]\(.+?\)\s*$/;
const HAS_PRICE = /₹|Rs\.?|INR|\d{3,}/;

for (const line of lines) {
  if (LINK_ONLY_LINE.test(line) && !HAS_PRICE.test(line)) {
    linkRunCount++;
    if (linkRunCount <= 4) cleaned.push(line); // keep first few, drop the rest of a long run
  } else {
    linkRunCount = 0;
    cleaned.push(line);
  }
}

// Step 4: Collapse 3+ consecutive blank lines into 1
let result = cleaned.join('\n').replace(/\n{3,}/g, '\n\n').trim();

// Step 5: Safety net — only if still huge (>40K chars), hard cut at last product-looking line
if (result.length > 40000) {
  const PRICE_LINE = /₹|Rs\.?|INR|\d{3,}/;
  const resultLines = result.split('\n');
  let lastProductLine = 15000; // fallback
  for (let i = resultLines.length - 1; i >= 0; i--) {
    if (PRICE_LINE.test(resultLines[i])) {
      lastProductLine = i + 5; // keep a few lines of context after last price
      break;
    }
  }
  result = resultLines.slice(0, lastProductLine).join('\n').trim();
}

return {
  json: {
    brand,
    sheet_tab: sheetTab,
    cleaned_markdown: result,
    original_chars: md.length,
    cleaned_chars: result.length,
    reduction_pct: Math.round((1 - result.length / md.length) * 100)
  }
};

const brand = $('Striping').item.json.brand;
const sheetTab = $('Striping').item.json.sheet_tab;

// ✅ safer input extraction
let raw = $input.item.json.message?.content 
       || $input.item.json.content 
       || $input.item.json.text 
       || '';

// 🧹 clean markdown
raw = raw.replace(/^```json\n?/,'').replace(/\n?```$/,'').trim();

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  return {
    json: {
      brand,
      sheet_tab: sheetTab,
      error: "Invalid JSON from previous step",
      raw_preview: raw.slice(0, 500),
      products: []
    }
  };
}

// ✅ support BOTH formats
let productArray = [];

if (Array.isArray(parsed)) {
  productArray = parsed;
} else if (Array.isArray(parsed.products)) {
  productArray = parsed.products;
}

// 📅 date
const today = new Date().toISOString().split('T')[0];

// ✅ normalize products
const products = productArray.map(p => ({
  brand,
  sheet_tab: sheetTab,
  name: (p.name || '').trim(),
  description: (p.description || '').trim(),
  price: !isNaN(Number(p.price)) ? Number(p.price) : null,
  mrp: !isNaN(Number(p.mrp)) ? Number(p.mrp) : null,
  category: (p.category || '').trim(),
  tags: Array.isArray(p.tags) ? p.tags.join(', ') : (p.tags || ''),
  scraped_at: today
}));

return {
  json: {
    brand,
    sheet_tab: sheetTab,
    count: products.length,
    products
  }
};

const all = $input.all();
const first = all[0].json;
const incoming = first.products || [];
const brand = first.brand;
const sheetTab = first.sheet_tab;
const existing = all.slice(1).map(i => i.json);
const map = {};
for (const r of existing) { const k = (r.name||'').toLowerCase().trim(); if (k) map[k] = r; }
const newP = [], updatedP = [], unchanged = [];
for (const p of incoming) {
  const k = (p.name||'').toLowerCase().trim();
  if (!k) continue;
  const ex = map[k];
  if (!ex) { newP.push({...p, change_type:'NEW'}); continue; }
  const priceChanged = String(ex.price) !== String(p.price);
  const mrpChanged = String(ex.mrp||'') !== String(p.mrp||'');
  const descChanged = (ex.description||'').trim() !== (p.description||'').trim();
  const catChanged = (ex.category||'').trim() !== (p.category||'').trim();
  const tagsChanged = (ex.tags||'').trim() !== (p.tags||'').trim();
  if (priceChanged || mrpChanged || descChanged || catChanged || tagsChanged) {
    updatedP.push({...p, old_price: ex.price, old_mrp: ex.mrp, change_type:'UPDATED',
      price_delta: priceChanged ? (p.price - parseFloat(ex.price||0)).toFixed(0) : 0 });
  } else {
    unchanged.push(p.name);
  }
}
const inNames = new Set(incoming.map(p => (p.name||'').toLowerCase().trim()));
const removed = existing.filter(r => r.name && !inNames.has((r.name||'').toLowerCase().trim())).map(r => r.name);
return [{ json: { brand, sheet_tab: sheetTab, has_changes: newP.length>0||updatedP.length>0||removed.length>0, new_products: newP, updated_products: updatedP, removed_products: removed, unchanged_count: unchanged.length, summary: { new_count: newP.length, updated_count: updatedP.length, removed_count: removed.length } } }];

const d = $input.item.json;
const tab = d.sheet_tab;
const rows = [...(d.new_products||[]), ...(d.updated_products||[])];
return rows.map(p => ({ json: {
  sheet_tab: tab,
  name: p.name,
  description: p.description,
  price: p.price,
  mrp: p.mrp || null,
  category: p.category,
  tags: p.tags,
  scraped_at: p.scraped_at || new Date().toISOString().split('T')[0]
} }));
